<?php declare(strict_types=1);
namespace SkyFi\System\Controllers;
use SkyFi\Shared\Http\{ApiResponse,Request,Response};
use SkyFi\System\Services\SystemAdministrationService;
final class BranchController extends SystemBaseController { public function __construct(private readonly SystemAdministrationService $service, \SkyFi\Rbac\Middleware\RequirePermissionMiddleware $p){parent::__construct($p);} public function index(Request $r): Response { $this->user($r,'system.view'); $res=$this->service->branches->list($r->query()); return new Response(200,['data'=>array_map(fn($x)=>['type'=>'branches','id'=>(string)$x['id'],'attributes'=>$x],$res['items']),'meta'=>$res['meta']]); } public function show(Request $r): Response { $this->user($r,'system.view'); $d=$this->service->branches->find($this->id($r)); return ApiResponse::resource('branches',(string)$d['id'],$d); } public function store(Request $r): Response { $u=$this->user($r,'system.manage'); $d=$this->service->saveBranch(null,$r->body(),$u,$r->ipAddress(),$r->userAgent()); return ApiResponse::resource('branches',(string)$d['id'],$d,201); } public function update(Request $r): Response { $u=$this->user($r,'system.manage'); $d=$this->service->saveBranch($this->id($r),$r->body(),$u,$r->ipAddress(),$r->userAgent()); return ApiResponse::resource('branches',(string)$d['id'],$d); } public function destroy(Request $r): Response { $u=$this->user($r,'system.manage'); $this->service->deleteBranch($this->id($r),$u,$r->ipAddress(),$r->userAgent()); return ApiResponse::noContent(); } public function activate(Request $r): Response { return $this->status($r,'active'); } public function deactivate(Request $r): Response { return $this->status($r,'inactive'); } private function status(Request $r,string $s): Response { $u=$this->user($r,'system.manage'); $d=$this->service->branchStatus($this->id($r),$s,$u,$r->ipAddress(),$r->userAgent()); return ApiResponse::resource('branches',(string)$d['id'],$d); }}
